#include <vector>
#include <priority_queue>
#include <tuple>
#include <algorithm>

using namespace std;

long long solve(vector<vector<long long>> grid, long long k) {
    int m = grid.size();
    int n = grid[0].size();
    vector<vector<vector<pair<int, int>>>> teleport_to(m, vector<vector<pair<int, int>>>(n));
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            long long val = grid[i][j];
            for (int x = 0; x < m; ++x) {
                for (int y = 0; y < n; ++y) {
                    if (grid[x][y] <= val) {
                        teleport_to[i][j].push_back({x, y});
                    }
                }
            }
        }
    }
    long long INF = 1e18;
    vector<vector<vector<long long>>> dp(m, vector<vector<long long>>(n, vector<long long>(k + 1, INF)));
    dp[0][0][0] = 0;
    priority_queue<tuple<long long, int, int, int>, vector<tuple<long long, int, int, int>>, greater<>> pq;
    pq.push({0, 0, 0, 0});
    vector<pair<int, int>> directions = {{0, 1}, {1, 0}};
    while (!pq.empty()) {
        long long cost = get<0>(pq.top());
        int i = get<1>(pq.top());
        int j = get<2>(pq.top());
        int t = get<3>(pq.top());
        pq.pop();
        if (i == m - 1 && j == n - 1) {
            return cost;
        }
        if (cost > dp[i][j][t]) continue;
        for (auto [di, dj] : directions) {
            int ni = i + di, nj = j + dj;
            if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                long long new_cost = cost + grid[ni][nj];
                if (new_cost < dp[ni][nj][t]) {
                    dp[ni][nj][t] = new_cost;
                    pq.push({new_cost, ni, nj, t});
                }
            }
        }
        for (auto [x, y] : teleport_to[i][j]) {
            if (t + 1 <= k) {
                long long new_t = t + 1;
                if (cost < dp[x][y][new_t]) {
                    dp[x][y][new_t] = cost;
                    pq.push({cost, x, y, new_t});
                }
            }
        }
    }
    return dp[m-1][n-1][k];
}
