#include <vector>
#include <priority_queue>
#include <tuple>
#include <algorithm>

using namespace std;

long long solve(vector<vector<long long>> grid, long long k) {
    int m = grid.size();
    int n = grid[0].size();

    // Precompute teleport_to
    vector<vector<vector<pair<int, int>>>> teleport_to(m, vector<vector<pair<int, int>>>(n));
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            long long val = grid[i][j];
            for (int x = 0; x < m; ++x) {
                for (int y = 0; y < n; ++y) {
                    if (grid[x][y] <= val) {
                        teleport_to[i][j].push_back({x, y});
                    }
                }
            }
        }
    }

    // Initialize DP
    vector<vector<vector<long long>>> dp(m, vector<vector<long long>>(n, vector<long long>(k+1, LLONG_MAX)));
    dp[0][0][0] = 0;

    // Priority queue: (-cost, i, j, t)
    priority_queue<tuple<long long, int, int, int>, vector<tuple<long long, int, int, int>>, greater<>> pq;
    pq.push( {0, 0, 0, 0} );

    // Directions: right and down
    vector<pair<int, int>> directions = { {0, 1}, {1, 0} };

    while (!pq.empty()) {
        auto [cost_neg, i, j, t] = pq.top();
        long long current_cost = -cost_neg;
        pq.pop();

        // Check if destination
        if (i == m-1 && j == n-1) {
            return current_cost;
        }

        // Skip if current cost is not the best
        if (current_cost > dp[i][j][t]) {
            continue;
        }

        // Process normal moves
        for (auto [di, dj] : directions) {
            int ni = i + di;
            int nj = j + dj;
            if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                long long new_cost = current_cost + grid[ni][nj];
                if (new_cost < dp[ni][nj][t]) {
                    dp[ni][nj][t] = new_cost;
                    pq.push( {-new_cost, ni, nj, t} );
                }
            }
        }

        // Process teleport moves
        for (auto [x, y] : teleport_to[i][j]) {
            if (t + 1 <= k) {
                long long new_t = t + 1;
                if (current_cost < dp[x][y][new_t]) {
                    dp[x][y][new_t] = current_cost;
                    pq.push( {-current_cost, x, y, new_t} );
                }
            }
        }
    }

    // If not found (should not happen)
    return dp[m-1][n-1][k];
}

